        node = _parse_expression(tokenizer)
        tokenizer.consume("OP", ")")
        return node

    raise ValueError(f"Unexpected token: {token[1]}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value

    if node.type == "unary":
        if node.operand is None:
            raise ValueError("Unary node has no operand")
        operand_value = evaluate(node.operand)
        if node.op == "-":
            return -operand_value
        return operand_value

    if node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Binary operation node missing operands")
        left_value = evaluate(node.left)
        right_value = evaluate(node.right)

        if node.op == "+":
            return left_value + right_value
        elif node.op == "-":
            return left_value - right_value
        elif node.op == "*":
            return left_value * right_value
        elif node.op == "/":
            if right_value == 0:
                raise ZeroDivisionError("Division by zero")
            return left_value / right_value
        else:
            raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
